use wasm_bindgen::prelude::*;

// -----------------------------------------------------------------------------
// Aeon Flow Frame Defs
// 10-byte wire format exactly as defined in flow-bridge.ts
// -----------------------------------------------------------------------------

pub const HEADER_SIZE: usize = 10;
pub const MAX_PAYLOAD_LENGTH: usize = 0xffffff;

// Flags mirror types.ts (assumed bitmasks based on the typescript tests)
pub const FORK: u8  = 0b00000001;
pub const RACE: u8  = 0b00000010;
pub const FOLD: u8  = 0b00000100;
pub const VENT: u8  = 0b00001000;
pub const FIN: u8   = 0b00010000;
pub const INTERFERE: u8 = 0b00100000;
pub const KNOT: u8      = 0b01000000;
pub const COLLAPSE: u8 = FOLD; // Synonym

// Knot crossing codes (2-bit)
pub const KNOT_VENT: u8 = 0b00;
pub const KNOT_FOLD: u8 = 0b01;
pub const KNOT_RACE: u8 = 0b10;
pub const KNOT_FORK: u8 = 0b11;

#[wasm_bindgen]
pub struct FlowFrame {
    pub stream_id: u16,
    pub sequence: u32,
    pub flags: u8,
    payload_len: u32,
    payload: Vec<u8>,
}

#[wasm_bindgen]
impl FlowFrame {
    pub fn create(stream_id: u16, sequence: u32, flags: u8, payload: &[u8]) -> Result<FlowFrame, JsValue> {
        if payload.len() > MAX_PAYLOAD_LENGTH {
            return Err(JsValue::from_str("Payload too large"));
        }
        Ok(FlowFrame {
            stream_id,
            sequence,
            flags,
            payload_len: payload.len() as u32,
            payload: payload.to_vec(),
        })
    }

    pub fn encode(&self) -> Vec<u8> {
        let mut buffer = Vec::with_capacity(HEADER_SIZE + self.payload.len());
        
        // 0-1: Stream ID (u16 BE)
        buffer.extend_from_slice(&self.stream_id.to_be_bytes());
        // 2-5: Sequence (u32 BE)
        buffer.extend_from_slice(&self.sequence.to_be_bytes());
        // 6: Flags
        buffer.push(self.flags);
        // 7-9: Length (24-bit BE)
        buffer.push(((self.payload_len >> 16) & 0xff) as u8);
        buffer.push(((self.payload_len >> 8) & 0xff) as u8);
        buffer.push((self.payload_len & 0xff) as u8);
        
        // Payload
        buffer.extend_from_slice(&self.payload);
        
        buffer
    }

    pub fn decode(bytes: &[u8], offset: usize) -> Result<FlowFrame, JsValue> {
        if bytes.len() - offset < HEADER_SIZE {
            return Err(JsValue::from_str("Buffer too small"));
        }

        let slice = &bytes[offset..];
        
        let stream_id = u16::from_be_bytes([slice[0], slice[1]]);
        let sequence = u32::from_be_bytes([slice[2], slice[3], slice[4], slice[5]]);
        let flags = slice[6];
        let length = ((slice[7] as u32) << 16) | ((slice[8] as u32) << 8) | (slice[9] as u32);

        if bytes.len() - offset < HEADER_SIZE + length as usize {
            return Err(JsValue::from_str("Buffer incomplete"));
        }

        let payload_start = offset + HEADER_SIZE;
        let payload_end = payload_start + length as usize;
        let payload = bytes[payload_start..payload_end].to_vec();

        Ok(FlowFrame {
            stream_id,
            sequence,
            flags,
            payload_len: length,
            payload,
        })
    }

    pub fn get_payload(&self) -> Vec<u8> {
        self.payload.clone()
    }
}

// -----------------------------------------------------------------------------
// Vectorized Quantum Runtime
// -----------------------------------------------------------------------------

#[wasm_bindgen]
pub struct QuantumRuntime {
    beta1: usize,
    paths: usize,
    trace: Vec<String>,
    /// Mitzvot enforcement: quarantined nodes cannot participate in consensus.
    quarantined: bool,
    /// Mitzvot enforcement: sabbath mode (zero mutations).
    sabbath_active: bool,
}

#[wasm_bindgen]
impl QuantumRuntime {
    #[wasm_bindgen(constructor)]
    pub fn new() -> QuantumRuntime {
        QuantumRuntime {
            beta1: 0,
            paths: 1,
            trace: Vec::new(),
            quarantined: false,
            sabbath_active: false,
        }
    }

    /// Sets the node's quarantine status (Tzara'at protocol).
    pub fn set_quarantine(&mut self, status: bool) {
        self.quarantined = status;
        self.trace.push(format!("TZARAAT: Quarantine set to {}", status));
    }

    /// Sets the node's sabbath status (Synchronization Boundary).
    pub fn set_sabbath(&mut self, active: bool) {
        self.sabbath_active = active;
        self.trace.push(format!("SABBATH: Sync boundary set to {}", active));
    }

    /// Jubilee operation: resets ownership mass (rounds/rejections) to ground state.
    pub fn jubilee(&mut self) {
        self.beta1 = 0;
        self.paths = 1;
        self.trace.push("JUBILEE: Ownership mass reset to ground state.".to_string());
    }

    /// Takes a raw Aeon FlowFrame byte buffer, processes the topology based on flags,
    /// and returns a resulting frame (simulating a zero-copy pass-through).
    pub fn process_frame(&mut self, encoded_bytes: &[u8]) -> Result<Vec<u8>, JsValue> {
        if self.quarantined {
            return Err(JsValue::from_str("NODE_QUARANTINED: Tzara'at detected, consensus participation blocked."));
        }

        let mut frame = FlowFrame::decode(encoded_bytes, 0)?;
        
        self.trace.push(format!("Seq: {}, Flags: {:02X}", frame.sequence, frame.flags));

        // Sabbath check: zero mutations allowed during sync boundary.
        if self.sabbath_active && (frame.flags & (FORK | RACE | FOLD | VENT | KNOT)) != 0 {
            return Err(JsValue::from_str("SABBATH_VIOLATION: Mutation attempted during synchronization interval."));
        }

        if (frame.flags & FORK) != 0 {
            // Simulated fork - we would read payload here to know how many paths
            self.beta1 += 1;
            self.paths += 1;
            frame.flags &= !FORK; // Clear flag after process
        }
        
        if (frame.flags & RACE) != 0 {
            self.paths = 1;
            // Retain beta1 until someone wins (in a real system)
            frame.flags &= !RACE;
        }
        
        if (frame.flags & FOLD) != 0 || (frame.flags & COLLAPSE) != 0 {
            self.beta1 = self.beta1.saturating_sub(1);
            self.paths = 1;
            frame.flags &= !(FOLD | COLLAPSE);
        }
        
        if (frame.flags & VENT) != 0 {
            self.beta1 = self.beta1.saturating_sub(1);
            self.paths = self.paths.saturating_sub(1);
            frame.flags &= !VENT;
        }
        
        if (frame.flags & INTERFERE) != 0 {
            frame.flags &= !INTERFERE;
        }

        // Knot-encoded payload: decode crossings and process each one.
        // The payload IS the packed knot binary.
        if (frame.flags & KNOT) != 0 {
            let payload = frame.get_payload();
            if let Ok(mut decoder) = PackedKnotDecoder::decode(&payload) {
                loop {
                    let crossing = decoder.next();
                    if crossing == 255 { break; }
                    match crossing {
                        KNOT_FORK => {
                            self.beta1 += 1;
                            self.paths += 1;
                        }
                        KNOT_RACE => {
                            self.paths = 1;
                        }
                        KNOT_FOLD => {
                            self.beta1 = self.beta1.saturating_sub(1);
                            self.paths = 1;
                        }
                        KNOT_VENT => {
                            self.beta1 = self.beta1.saturating_sub(1);
                            self.paths = self.paths.saturating_sub(1);
                        }
                        _ => {}
                    }
                    self.trace.push(format!("Knot crossing {}: {:02b}", decoder.position() - 1, crossing));
                }
            }
            frame.flags &= !KNOT;
        }

        Ok(frame.encode())
    }

    pub fn metrics(&self) -> String {
        format!("Paths: {}, Beta1: {}", self.paths, self.beta1)
    }

    pub fn get_trace(&self) -> String {
        self.trace.join("\n")
    }
}

// -----------------------------------------------------------------------------
// Packed Knot Decoder
// Two bits per crossing. The knot IS the wire format. Zero overhead.
// Lean theorems: random_access, zero_overhead, compose_assoc, pack_unpack.
// -----------------------------------------------------------------------------

const KNOT_HEADER_SIZE: usize = 8; // 2 magic + 1 version + 1 reserved + 4 count

#[wasm_bindgen]
pub struct PackedKnotDecoder {
    crossings: Vec<u8>,
    count: u32,
    cursor: u32,
}

#[wasm_bindgen]
impl PackedKnotDecoder {
    /// Decode a packed knot from its serialized bytes.
    /// Header: 'KN' magic (2), version (1), reserved (1), crossing count (4).
    /// Followed by ceil(count/4) bytes of 2-bit crossings.
    #[wasm_bindgen(constructor)]
    pub fn decode(bytes: &[u8]) -> Result<PackedKnotDecoder, JsValue> {
        if bytes.len() < KNOT_HEADER_SIZE {
            return Err(JsValue::from_str("Knot too short for header"));
        }
        let magic = ((bytes[0] as u16) << 8) | bytes[1] as u16;
        if magic != 0x4B4E {
            return Err(JsValue::from_str("Invalid knot magic"));
        }
        let count = ((bytes[4] as u32) << 24)
            | ((bytes[5] as u32) << 16)
            | ((bytes[6] as u32) << 8)
            | bytes[7] as u32;
        let crossing_bytes = ((count + 3) / 4) as usize;
        if bytes.len() < KNOT_HEADER_SIZE + crossing_bytes {
            return Err(JsValue::from_str("Knot truncated"));
        }
        let crossings = bytes[KNOT_HEADER_SIZE..KNOT_HEADER_SIZE + crossing_bytes].to_vec();
        Ok(PackedKnotDecoder {
            crossings,
            count,
            cursor: 0,
        })
    }

    /// Yield the next 2-bit crossing. Returns 255 when exhausted.
    pub fn next(&mut self) -> u8 {
        if self.cursor >= self.count {
            return 255;
        }
        let i = self.cursor as usize;
        self.cursor += 1;
        (self.crossings[i >> 2] >> (6 - 2 * (i & 3))) & 3
    }

    /// Random access: read crossing at index i. Returns 255 if out of bounds.
    /// Proven O(1) by random_access theorem.
    pub fn get(&self, index: u32) -> u8 {
        if index >= self.count {
            return 255;
        }
        let i = index as usize;
        (self.crossings[i >> 2] >> (6 - 2 * (i & 3))) & 3
    }

    /// Self-modification: overwrite crossing at index.
    /// The topology rewrites itself during execution.
    pub fn set(&mut self, index: u32, op: u8) {
        if index >= self.count || op > 3 {
            return;
        }
        let i = index as usize;
        let byte_idx = i >> 2;
        let shift = 6 - 2 * (i & 3);
        self.crossings[byte_idx] =
            (self.crossings[byte_idx] & !(3 << shift)) | ((op & 3) << shift);
    }

    /// Reset cursor to beginning.
    pub fn reset(&mut self) {
        self.cursor = 0;
    }

    /// Total crossing count.
    pub fn len(&self) -> u32 {
        self.count
    }

    /// Current cursor position.
    pub fn position(&self) -> u32 {
        self.cursor
    }
}

// -----------------------------------------------------------------------------
// Gnosis Slippage Formal Proof Validation 
// Binds GnosisProofs.lean formal guarantees into WASM execution environment
// -----------------------------------------------------------------------------

#[wasm_bindgen]
pub struct ExecutionCertificate {
    pub expected_profit: f64,
    pub spread_cost: f64,
    pub latency: f64,
    pub alpha_decay: f64,
}

#[wasm_bindgen]
impl ExecutionCertificate {
    #[wasm_bindgen(constructor)]
    pub fn new(expected_profit: f64, spread_cost: f64, latency: f64, alpha_decay: f64) -> ExecutionCertificate {
        ExecutionCertificate {
            expected_profit,
            spread_cost,
            latency,
            alpha_decay,
        }
    }
}

#[wasm_bindgen]
pub fn check_gnosis_slippage_guarantee(cert: &ExecutionCertificate) -> bool {
    let effective_slippage = cert.spread_cost + (cert.latency / cert.alpha_decay) * cert.expected_profit;
    let is_toxic = cert.expected_profit <= effective_slippage;
    cert.latency >= 0.0 && cert.alpha_decay > 0.0 && cert.expected_profit >= 0.0 && !is_toxic
}

// -----------------------------------------------------------------------------
// Delayed Projection Kernel
// Quantum advantage on classical hardware — at the wire level.
//
// Lean backing:
//   DelayedProjectionRuntime.lean — formal proofs (zero sorry)
//   ShannonMirroredRooms.lean     — self-similar projection theory
//
// The bit is a 2D projection of the trit. Quantum computing is a
// Wallington rotation. Both defer the 3→2 projection to the end
// of a staged pipeline.
//
// This kernel tracks projection delay at the frame level:
//   FORK  → delayed op (stays in trit space, depth += 1)
//   RACE  → delayed op (amplification, no projection yet)
//   FOLD  → projection (collapses to bit space, measures)
//   VENT  → free discard (encode_is_free from VoidUring.lean)
//
// The information advantage is 3^D - 2^D where D = delay depth.
// This grows exponentially — the mirror is always bigger.
// -----------------------------------------------------------------------------

/// Projection stage at the kernel level.
#[wasm_bindgen]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum KernelProjectionStage {
    /// Operating in trit basis. No projection yet.
    Unprojected = 0,
    /// Projection in progress.
    Projecting = 1,
    /// Projected to bit basis. Result available.
    Projected = 2,
}

/// Wallington-quantum stage at the kernel level.
#[wasm_bindgen]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum KernelWallingtonStage {
    /// Superposition initialized. No operations yet.
    LoadIsolated = 0,
    /// Operating in trit basis (delayed ops in flight).
    DelayedOps = 1,
    /// Measurement / allocation complete.
    FinalProjection = 2,
}

/// Delayed Projection Kernel — projection-delay tracking at wire speed.
///
/// Sits alongside `QuantumRuntime` and processes the same FlowFrames,
/// but adds projection-delay accounting. Every FORK that doesn't
/// immediately FOLD increases the delay depth; the advantage grows
/// as 3^D / 2^D.
///
/// This is the kernel surface that gnosis-uring and WASM-SIMD use
/// to make scheduling decisions. A high delay depth means the mirror
/// (unscheduling mesh) has exponentially more states to work with.
#[wasm_bindgen]
pub struct DelayedProjectionKernel {
    /// Number of deferred operations (trit basis).
    delay_depth: u32,
    /// Number of projected operations (bit basis).
    projected_ops: u32,
    /// Total operations processed.
    total_ops: u64,
    /// Current projection stage.
    stage: KernelProjectionStage,
    /// Current Wallington stage.
    wallington_stage: KernelWallingtonStage,
    /// Vented payloads (free — encode_is_free).
    total_vents: u64,
    /// Clinamen spent (reads from mirror — 1 per read).
    clinamen_spent: u64,
    /// Trace log.
    trace: Vec<String>,
}

#[wasm_bindgen]
impl DelayedProjectionKernel {
    #[wasm_bindgen(constructor)]
    pub fn new() -> DelayedProjectionKernel {
        DelayedProjectionKernel {
            delay_depth: 0,
            projected_ops: 0,
            total_ops: 0,
            stage: KernelProjectionStage::Unprojected,
            wallington_stage: KernelWallingtonStage::LoadIsolated,
            total_vents: 0,
            clinamen_spent: 0,
            trace: Vec::new(),
        }
    }

    /// Process a FlowFrame through the delayed projection kernel.
    ///
    /// FORK: delayed op — stays in trit space. depth += 1.
    /// RACE: delayed op — amplification, no projection.
    /// FOLD: projection — collapses to bit space.
    /// VENT: free discard — vented to mirror, no cost.
    /// KNOT: each crossing processed individually.
    pub fn process_frame(&mut self, encoded_bytes: &[u8]) -> Result<Vec<u8>, JsValue> {
        let frame = FlowFrame::decode(encoded_bytes, 0)?;

        if (frame.flags & FORK) != 0 {
            self.delay_depth += 1;
            self.total_ops += 1;
            self.stage = KernelProjectionStage::Unprojected;
            if self.wallington_stage == KernelWallingtonStage::LoadIsolated {
                self.wallington_stage = KernelWallingtonStage::DelayedOps;
            }
            self.trace.push(format!(
                "FORK: delay_depth={}, trit_states={}, bit_states={}, advantage={}",
                self.delay_depth,
                self.trit_states(),
                self.bit_states(),
                self.information_advantage()
            ));
        }

        if (frame.flags & RACE) != 0 {
            // Race is amplification — stays in trit space
            self.total_ops += 1;
            self.trace.push(format!(
                "RACE: amplification at depth={}, ratio={:.2}",
                self.delay_depth,
                self.advantage_ratio()
            ));
        }

        if (frame.flags & FOLD) != 0 || (frame.flags & COLLAPSE) != 0 {
            // FOLD is projection — collapses to bit space
            let saved = self.information_advantage();
            self.projected_ops += 1;
            self.total_ops += 1;
            self.stage = KernelProjectionStage::Projected;
            self.wallington_stage = KernelWallingtonStage::FinalProjection;
            self.trace.push(format!(
                "FOLD/PROJECT: depth={}, states_saved={}, projected_ops={}",
                self.delay_depth, saved, self.projected_ops
            ));
            // Reset delay depth for next pipeline stage
            self.delay_depth = 0;
        }

        if (frame.flags & VENT) != 0 {
            // Vent is free (VoidUring.lean: encode_is_free)
            self.total_vents += 1;
            self.trace.push(format!(
                "VENT: free discard #{}, clinamen_spent={}",
                self.total_vents, self.clinamen_spent
            ));
        }

        // Knot crossings: process each one through the projection kernel
        if (frame.flags & KNOT) != 0 {
            let payload = frame.get_payload();
            if let Ok(mut decoder) = PackedKnotDecoder::decode(&payload) {
                loop {
                    let crossing = decoder.next();
                    if crossing == 255 { break; }
                    match crossing {
                        KNOT_FORK => {
                            self.delay_depth += 1;
                            self.total_ops += 1;
                        }
                        KNOT_RACE => {
                            self.total_ops += 1;
                        }
                        KNOT_FOLD => {
                            self.projected_ops += 1;
                            self.total_ops += 1;
                            self.stage = KernelProjectionStage::Projected;
                            self.delay_depth = 0;
                        }
                        KNOT_VENT => {
                            self.total_vents += 1;
                        }
                        _ => {}
                    }
                }
            }
        }

        Ok(frame.encode())
    }

    // ─── Information Advantage ───────────────────────────────────

    /// 3^D — states available in trit (unprojected) space.
    pub fn trit_states(&self) -> f64 {
        3.0_f64.powi(self.delay_depth as i32)
    }

    /// 2^D — states available in bit (projected) space.
    pub fn bit_states(&self) -> f64 {
        2.0_f64.powi(self.delay_depth as i32)
    }

    /// 3^D - 2^D — the mirror dividend.
    pub fn information_advantage(&self) -> f64 {
        self.trit_states() - self.bit_states()
    }

    /// 3^D / 2^D — how much bigger the mirror is.
    pub fn advantage_ratio(&self) -> f64 {
        if self.delay_depth == 0 {
            return 1.0;
        }
        self.trit_states() / self.bit_states()
    }

    /// Projection loss per step: always 1 (self-similar at all scales).
    pub fn projection_loss(&self) -> u32 {
        1
    }

    // ─── Queries ─────────────────────────────────────────────────

    /// Current delay depth.
    pub fn get_delay_depth(&self) -> u32 {
        self.delay_depth
    }

    /// Total projected operations.
    pub fn get_projected_ops(&self) -> u32 {
        self.projected_ops
    }

    /// Total operations.
    pub fn get_total_ops(&self) -> u64 {
        self.total_ops
    }

    /// Total vents (free discards).
    pub fn get_total_vents(&self) -> u64 {
        self.total_vents
    }

    /// Total clinamen spent (mirror reads).
    pub fn get_clinamen_spent(&self) -> u64 {
        self.clinamen_spent
    }

    /// Record a mirror read (costs 1 clinamen).
    pub fn mirror_read(&mut self) {
        self.clinamen_spent += 1;
    }

    /// Metrics string.
    pub fn metrics(&self) -> String {
        format!(
            "delay_depth={} projected_ops={} total_ops={} advantage_ratio={:.2} trit_states={:.0} bit_states={:.0} vents={} clinamen={}",
            self.delay_depth,
            self.projected_ops,
            self.total_ops,
            self.advantage_ratio(),
            self.trit_states(),
            self.bit_states(),
            self.total_vents,
            self.clinamen_spent
        )
    }

    /// Trace log.
    pub fn get_trace(&self) -> String {
        self.trace.join("\n")
    }

    /// Reset kernel state.
    pub fn reset(&mut self) {
        self.delay_depth = 0;
        self.projected_ops = 0;
        self.total_ops = 0;
        self.stage = KernelProjectionStage::Unprojected;
        self.wallington_stage = KernelWallingtonStage::LoadIsolated;
        self.total_vents = 0;
        self.clinamen_spent = 0;
        self.trace.clear();
    }
}

// -----------------------------------------------------------------------------
// Frf witness merges — wasm surface aligned with `bitwise::frf_witness` /
// `Gnosis.FrfWitnessTower`. Kept local (no `bitwise` dep) so this WASM stays tiny.
// -----------------------------------------------------------------------------

#[wasm_bindgen]
pub fn frf_triad_add_fin3(a: u8, b: u8) -> Result<u8, JsValue> {
    bitwise_local_triad_add_fin3(a, b).ok_or_else(|| {
        JsValue::from_str("frf_triad_add_fin3 expects digits in 0..3 (Fin 3 representatives)")
    })
}

#[wasm_bindgen]
pub fn frf_triad_merge_fin3_digits(digits: &[u8]) -> Result<u8, JsValue> {
    bitwise_local_triad_merge_fin3_digits(digits)
        .map_err(|_| JsValue::from_str("frf_triad_merge_fin3_digits expects each digit in 0..3"))
}

#[wasm_bindgen]
pub fn frf_xor_merge_bits(bits: &[u8]) -> Result<u8, JsValue> {
    bitwise_local_xor_merge_bits(bits)
        .map_err(|_| JsValue::from_str("frf_xor_merge_bits expects each entry in {0,1}"))
}

#[wasm_bindgen]
pub fn frf_fin_three_parity_bit(digit: u8) -> Result<u8, JsValue> {
    if digit >= 3 {
        return Err(JsValue::from_str(
            "frf_fin_three_parity_bit expects digit in 0..3",
        ));
    }
    Ok(if digit == 1 { 1 } else { 0 })
}

fn bitwise_local_triad_add_fin3(a: u8, b: u8) -> Option<u8> {
    if a >= 3 || b >= 3 {
        return None;
    }
    Some((a + b) % 3)
}

fn bitwise_local_triad_merge_fin3_digits(digits: &[u8]) -> Result<u8, ()> {
    let mut acc = 0u8;
    for &d in digits {
        if d >= 3 {
            return Err(());
        }
        acc = bitwise_local_triad_add_fin3(acc, d).ok_or(())?;
    }
    Ok(acc)
}

fn bitwise_local_xor_merge_bits(bits: &[u8]) -> Result<u8, ()> {
    let mut acc = 0u8;
    for &b in bits {
        if b > 1 {
            return Err(());
        }
        acc ^= b;
    }
    Ok(acc)
}

#[cfg(test)]
mod frf_witness_inline_tests {
    use super::*;

    #[test]
    fn mirrors_bitwise_triad_anchor() {
        assert_eq!(
            bitwise_local_triad_merge_fin3_digits(&[1, 2]).unwrap(),
            bitwise_local_triad_merge_fin3_digits(&[2, 1]).unwrap()
        );
    }
}

#[cfg(test)]
mod foil_compressor_cascade_tests {
    //! FOIL's delayed-projection kernel as a jet-engine compressor cascade.
    //!
    //! Each FORK frame is a delayed-projection stage that keeps the op in trit (3-state) space
    //! instead of projecting to bit (2-state) space, multiplying the mirror's information ratio by
    //! exactly 3/2 (`trit_states/bit_states = 3^D/2^D`, see `advantage_ratio`). So a depth-`D`
    //! delay pipeline is a `D`-stage compressor cascade with overall ratio `(3/2)^D` = the product
    //! of the stage ratios — `Gnosis.MathJetEngine.overallRatio_append`, realized on FOIL's real
    //! kernel state.
    use super::*;
    use gnosis_engine_core::{compose, homomorphism_holds, overall_ratio, CascadeReport, Stage};

    /// Drive `d` FORK frames through the real kernel, returning it at `delay_depth = d`.
    fn kernel_at_depth(d: u32) -> DelayedProjectionKernel {
        let mut k = DelayedProjectionKernel::new();
        let fork_frame = FlowFrame::create(0, 0, FORK, &[]).unwrap().encode();
        for _ in 0..d {
            k.process_frame(&fork_frame).unwrap();
        }
        k
    }

    /// The FOIL delay cascade at depth `d`: `d` stages each with ratio 3/2.
    fn delay_stages(d: u32) -> Vec<Stage> {
        (0..d).map(|i| Stage::new(format!("delay-fork-{i}"), 1.5)).collect()
    }

    #[test]
    fn delay_advantage_is_the_cascade_product() {
        // For each real kernel depth, the kernel's measured advantage_ratio (3^D/2^D) equals the
        // compressor-cascade product of the per-stage 3/2 ratios.
        for d in 0u32..=12 {
            let k = kernel_at_depth(d);
            assert_eq!(k.get_delay_depth(), d, "kernel reached depth {d}");
            let predicted = overall_ratio(&delay_stages(d));
            let measured = k.advantage_ratio(); // 3^D / 2^D from real kernel state
            assert!(
                (predicted - measured).abs() <= 1e-9 * measured.max(1.0),
                "depth {d}: cascade product {predicted} != kernel advantage {measured}",
            );
        }
    }

    #[test]
    fn delay_cascade_obeys_append_homomorphism() {
        // Stacking a depth-3 sub-pipeline onto a depth-5 sub-pipeline gives a depth-8 pipeline,
        // and the overall ratio multiplies — verified against the real kernel at depth 8.
        let low = delay_stages(3); // (3/2)^3
        let high = delay_stages(5); // (3/2)^5
        assert!(homomorphism_holds(&low, &high, 1e-9));
        let stacked = compose(&low, &high); // depth 8
        let k8 = kernel_at_depth(8);
        let report = CascadeReport::new("FOIL delay depth 8", stacked, k8.advantage_ratio());
        assert!(report.law_holds(1e-9), "{}", report.summary());
        // (3/2)^8 = 6561/256 ~= 25.6289
        assert!((report.predicted_product - 25.628906).abs() < 1e-4);
    }
}

#[cfg(test)]
mod foil_speed_of_light_tests {
    //! monster/FOIL carries the %c metric with Lean proof. The FOIL grassmannian cache hit pays
    //! zero compute — it transmits a pre-computed result — so it rides the information front at
    //! 100% c (the photon, `Gnosis.RuntimeSpeedOfLightPercent.cache_hit_is_luminal`). A cold run
    //! recomputes and is strictly subluminal. Over a workload, monster's %c is its cache warmth.
    use gnosis_engine_core::speed_of_light::{
        c_percent, c_percent_from_hit_rate, SpeedOfLightReport, CACHE_HIT_C_PERCENT,
    };

    #[test]
    fn foil_cache_hit_rides_the_front() {
        // A grassmannian skip: compute 0, pure transmission -> 100% c.
        assert_eq!(c_percent(2.4, 0.0), CACHE_HIT_C_PERCENT);
        // A cold recompute (e.g. fib40 ~ 5_779_000_000 ns vs ~ns transmit) is deeply subluminal.
        assert!(c_percent(2.4, 5_779_000_000.0) < 1.0);
    }

    #[test]
    fn monster_percent_c_is_cache_warmth() {
        // The documented warmth ladder maps directly to %c.
        assert_eq!(c_percent_from_hit_rate(5, 100), 5.0); // default
        assert_eq!(c_percent_from_hit_rate(60, 100), 60.0); // + entropy + RF + resident
        let warm = SpeedOfLightReport::from_hits("monster-foil", 60, 100);
        assert_eq!(warm.percent_c, 60.0);
        assert!(!warm.is_luminal());
        let photon = SpeedOfLightReport::from_hits("monster-foil", 100, 100);
        assert!(photon.is_luminal()); // 100% warm = rides the front
        assert_eq!(photon.theorem_ids.len(), 4);
    }
}
